// The previous attempt put every assert inside `if H1 && H2 { ... }`,
// so the asserted conjuncts only lived in that branch and were
// discarded before the postcondition was checked. This time, expose
// the unfolding of `next_ensures` for both r1 and r2 as
// UNCONDITIONAL top-level implications. Each one is a tautology that
// Verus discharges by inlining the open spec body of `next_ensures`,
// but it lifts the six conjuncts into the proof context where z3 can
// pattern-match them symmetrically across the two runs.

let (ok1, res1) = r1;
let (ok2, res2) = r2;
let er1 = res1@;
let er2 = res2@;

// Conjunct 1: ok == new_netc.ok() — exposes the link from r_.0 to
// post_netc.ok() symmetrically for both runs.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ok1 == post1_netc.ok());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ok2 == post2_netc.ok());

// Conjunct 2: ok implies invariants on (post_self, post_netc).
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> post2_self_.invariants(&post2_netc.my_end_point())));

// Conjunct 3: ok implies the abstract `next` relation holds with the
// same pre@ on both sides. This is the crucial pairing for z3 — it
// must instantiate the existential `step` in `next` consistently
// across r1/r2 to discharge determinism.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> HostState::next(pre_self_.view(), post1_self_.view(), er1.ios)));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> HostState::next(pre_self_.view(), post2_self_.view(), er2.ios)));

// Conjunct 4: ok implies event_seq() == ios — links the synthetic
// ios used by `next` back to the recvs/clocks/sends triple that
// drives the determinism predicate via EventResults::view().
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> er1.event_seq() == er1.ios));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> er2.event_seq() == er2.ios));

// Conjunct 5: history-append equation, the main constraint on
// post_netc.view() (whose history field is otherwise free).
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((ok1 || er1.sends.len() > 0)
        ==> post1_netc.history() == pre_netc.history() + er1.event_seq()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((ok2 || er2.sends.len() > 0)
        ==> post2_netc.history() == pre_netc.history() + er2.event_seq()));

// Conjunct 6: well_typed_events. The forall quantifiers in this body
// are the most likely source of the trigger gap; surfacing the
// predicate explicitly for both runs forces matching instantiations.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> er1.well_typed_events());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> er2.well_typed_events());

// Unfold event_seq so its three-way concatenation is visible.
assert(er1.event_seq() == er1.recvs + er1.clocks + er1.sends);
assert(er2.event_seq() == er2.recvs + er2.clocks + er2.sends);

// Unfold the determinism predicate itself so each conjunct of the
// conclusion is named separately. This gives z3 a single point at
// which to attempt to discharge the whole equality from the six
// conjuncts above.
assert(det_real_next_impl_equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc)
    == ((r1.0 == r2.0)
        && ((r1.1)@.view() == (r2.1)@.view())
        && (post1_self_@ == post2_self_@)
        && (post1_netc.view() == post2_netc.view())));
